const quotes = $input.first().json;
const THRESHOLD = parseFloat($env.ALERT_THRESHOLD_PCT ?? '3');

const enriched = quotes.map(stock => {
  const changePct = stock.changesPercentage ?? 0;
  const vol = stock.volume ?? 0;
  const avgVol = stock.avgVolume ?? 1;
  const volRatio = parseFloat((vol / avgVol).toFixed(2));

  let signal = 'NEUTRAL';
  if (changePct >= THRESHOLD) signal = 'STRONG_BULLISH';
  else if (changePct >= 1.5) signal = 'BULLISH';
  else if (changePct <= -THRESHOLD) signal = 'STRONG_BEARISH';
  else if (changePct <= -1.5) signal = 'BEARISH';

  return {
    symbol: stock.symbol,
    name: stock.name,
    price: stock.price,
    change: stock.change,
    changePct: parseFloat(changePct.toFixed(2)),
    volume: vol,
    avgVolume: avgVol,
    volRatio,
    marketCap: stock.marketCap,
    signal,
    volumeAlert: volRatio > 1.8,
    needsAlert: signal.includes('STRONG') || volRatio > 1.8,
    timestamp: new Date().toISOString(),
    emoji: signal.includes('BULL') ? '🟢' : signal.includes('BEAR') ? '🔴' : '🟡'
  };
});

return enriched.map(item => ({ json: item }));

const items = $input.all();

const alertLines = items.map(i => {
  const d = i.json;
  const volNote = d.volumeAlert ? ` | 📊 Vol spike x${d.volRatio}` : '';
  return `${d.emoji} *${d.symbol}* (${d.name})\n   Price: $${d.price}  |  Change: ${d.changePct > 0 ? '+' : ''}${d.changePct}%${volNote}\n   Signal: \`${d.signal}\``;
}).join('\n\n');

const ts = new Date().toLocaleString('en-US', { timeZone: 'America/New_York', dateStyle: 'medium', timeStyle: 'short' });

return [{
  json: {
    slackBlocks: [
      { type: 'header', text: { type: 'plain_text', text: '📈 FinPulse Market Alert', emoji: true } },
      { type: 'section', text: { type: 'mrkdwn', text: `*Scan time:* ${ts} ET  |  *Alerts:* ${items.length}` } },
      { type: 'divider' },
      { type: 'section', text: { type: 'mrkdwn', text: alertLines } },
      { type: 'context', elements: [{ type: 'mrkdwn', text: '_FinPulse Automation | Source: Financial Modeling Prep_' }] }
    ],
    alertCount: items.length
  }
}];

const items = $input.all();
return items.map(i => {
  const d = i.json;
  return {
    json: {
      Timestamp: d.timestamp,
      Symbol: d.symbol,
      Name: d.name,
      Price: d.price,
      Change: d.change,
      'Change %': d.changePct,
      Volume: d.volume,
      'Vol Ratio': d.volRatio,
      'Market Cap': d.marketCap,
      Signal: d.signal,
      'Vol Alert': d.volumeAlert ? 'YES' : 'NO'
    }
  };
});

const hour = new Date().getHours();
if (hour !== 17) return [];

const items = $input.all();
const sorted = [...items].sort((a, b) => b.json.changePct - a.json.changePct);
const top3 = sorted.slice(0, 3);
const bot3 = sorted.slice(-3).reverse();

const fmt = d => `${d.emoji} *${d.symbol}*: ${d.changePct > 0 ? '+' : ''}${d.changePct}%  ($${d.price})`;

const text = [
  '📊 *FinPulse – End-of-Day Summary*',
  '',
  '*🏆 Top Performers*',
  ...top3.map(i => fmt(i.json)),
  '',
  '*📉 Bottom Performers*',
  ...bot3.map(i => fmt(i.json)),
  '',
  `_${new Date().toDateString()} | ${items.length} symbols tracked_`
].join('\n');

return [{ json: { summaryText: text } }];
